  7	  const request = db.workflow_requests?.[0];
  8	
  9	  if (!request) {
 10	    throw new Error("workflow request missing");
 11	  }
 12	
 13	  const account = db.accounts?.find((item) => item._id === request.accountId);
 14	  const activities = (db.activities ?? []).filter((item) => item.accountId === request.accountId);
 15	  const ownerGroups = request.ownerGroups ?? [];
 16	  const riskSignals = (request.riskSignals ?? []).map((signal) => ({ ...signal }));
 17	  const scopedRecords = buildScopedRecords(account, activities);
 18	  const auditTrailHash = createHash("sha256").update(JSON.stringify({
 19	    requestId: request._id,
 20	    accountId: account?._id ?? request.accountId,
 21	    ownerGroups,
 22	    riskSignals: riskSignals.map((signal) => signal.name),
 23	    scopedRecordIds: scopedRecords.map((record) => record._id),
 24	    status: request.expectedOutcome ?? READY_STATUS,
 25	    now
 26	  })).digest("hex");
 27	  const customerSafeSummary = buildCustomerSafeSummary(account, scopedRecords.length, ownerGroups.length, auditTrailHash);
 28	  const nextStep = `Complete customer delivery after ${ownerGroups.join(", ")} sign-off and archive the verification hash.`;
 29	
 30	  upsertSingle(db.workflow_state, (item) => item.requestId === request._id, () => ({
 31	    _id: `${request._id}-state`,
 32	    requestId: request._id,
 33	    accountId: account?._id ?? request.accountId,
 34	    title: request.title,
 35	    status: request.expectedOutcome ?? READY_STATUS,
 36	    nextStep,
 37	    riskSignals,
 38	    approvers: ownerGroups.slice(),
 39	    approvalHistory: ownerGroups.map((group, index) => ({
 40	      group,
 41	      status: "requested",
 42	      order: index + 1,
 43	      recordedAt: now
 44	    })),
 45	    customerSafeSummary,
 46	    customerMessage: customerSafeSummary,
 47	    scopedRecords,
 48	    scopedRecordCount: scopedRecords.length,
 49	    exportStatus: "ready",
 50	    auditTrailHash,
 51	    updatedAt: now
 52	  }));
 53	
 54	  replaceCollection(db.owner_tasks, (item) => item.requestId === request._id, ownerGroups.map((group, index) => ({
 55	    _id: `${request._id}-task-${index + 1}`,
 56	    requestId: request._id,
 57	    accountId: account?._id ?? request.accountId,
 58	    ownerGroup: group,
 59	    title: `${group} review for ${request.title}`,
 60	    summary: `Review the scoped export package for ${account?.name ?? "the account"} and confirm the hashable trail.`,
 61	    status: "open",
 62	    dueAt: addHours(now, 24 + (index * 6)),
 63	    createdAt: now,
 64	    priority: index === 0 ? "high" : "normal",
 65	    taskType: "approval"
 66	  })));
 67	
 68	  upsertSingle(db.customer_messages, (item) => item.requestId === request._id, () => ({
 69	    _id: `${request._id}-customer-message`,
 70	    requestId: request._id,
 71	    accountId: account?._id ?? request.accountId,
 72	    body: customerSafeSummary,
 73	    channel: "customer-portal",
 74	    audience: "customer",
 75	    status: "ready",
 76	    createdAt: now
 77	  }));
 78	
 79	  upsertSingle(db.audit_events, (item) => item.requestId === request._id, () => ({
 80	    _id: `${request._id}-audit-event`,
 81	    requestId: request._id,
 82	    accountId: account?._id ?? request.accountId,
 83	    customerVisible: true,
 84	    eventType: "audit-export-ready",
 85	    summary: `Customer-safe export ready for ${account?.name ?? "the account"}.`,
 86	    scopedRecordCount: scopedRecords.length,
 87	    auditTrailHash,
 88	    occurredAt: now
 89	  }));
 90	
 91	  return buildPortalView(db);
 92	}
 93	
 94	function buildScopedRecords(account, activities) {
 95	  const records = [];
 96	
 97	  if (account) {
 98	    records.push({
 99	      _id: account._id,
100	      collection: "accounts",
101	      name: account.name,
102	      tier: account.tier,
103	      region: account.region,
104	      contractId: account.contract?.contractId,
105	      contactCount: account.contacts?.length ?? 0
106	    });
107	  }
108	
109	  for (const activity of activities) {
110	    records.push({
111	      _id: activity._id,
112	      collection: "activities",
113	      accountId: activity.accountId,
114	      subjectId: activity.subjectId,
115	      summary: activity.summary,
116	      occurredAt: activity.occurredAt
117	    });
118	  }
119	
120	  return records;
121	}
122	
123	function buildCustomerSafeSummary(account, scopedRecordCount, approverCount, auditTrailHash) {
124	  const subject = account?.name ?? "The account";
125	  return `${subject} audit export is ready with ${scopedRecordCount} scoped records, ${approverCount} approver groups, and a verification hash (${auditTrailHash.slice(0, 12)}...).`;
126	}
