128	function addHours(now, hours) {
129	  return new Date(new Date(now).getTime() + (hours * 60 * 60 * 1000)).toISOString();
130	}
131	
132	function upsertSingle(collection, predicate, create) {
133	  const index = collection.findIndex(predicate);
134	  const next = create();
135	
136	  if (index >= 0) {
137	    collection[index] = next;
138	    return next;
139	  }
140	
141	  collection.push(next);
142	  return next;
143	}
144	
145	function replaceCollection(collection, predicate, entries) {
146	  for (let index = collection.length - 1; index >= 0; index -= 1) {
147	    if (predicate(collection[index])) {
148	      collection.splice(index, 1);
149	    }
150	  }
151	
152	  collection.push(...entries);
153	  return entries;
154	}
